/* DND2024:????????????????????? */
UPDATE rules.default_2024_race
SET description = 'Аасимары — это смертные, которые несут искру Верхних планов в своих душах. Будь то потомки ангельских существ или те, кто был наделён небесной силой, они могут разжечь эту искру, чтобы принести свет, исцеление и ярость небес.
Аасимары могут появляться в любом поселении смертных. Они похожи на своих родителей, но живут до 160 лет и имеют черты, намекающие на их небесное происхождение, такие как веснушки с металлическим блеском, светящиеся глаза, нимб или цвет кожи, как у ангелов (серебряный, опалово-зелёный или медно-красный). Эти черты начинают проявляться постепенно, становясь очевидными, когда аасимар учится полностью раскрывать свою небесную природу.'::text
WHERE code = 'AASIMAR'::text;

UPDATE rules.default_2024_race
SET description = 'Боггарты — маленькие, коренастые гоблиноиды, обитающие в мире Лорвина–Тенеборья. Они обладают звериными физическими чертами, включая рога и морды, похожие на морды животных. За пределами этих общих признаков внешний вид боггартов сильно различается: один может напоминать ежа с колючей шерстью и бусинками-глазами, тогда как другой — иметь свиное рыло и мясистые уши. Боггарты любят варить зелья и обычно тяготеют к определённым областям мастерства, как описано ниже.
В Лорвине. Боггарты Лорвина рождаются в общинных норах, где законы и иерархии считаются скорее рекомендациями. Самые старые и могущественные боггарты, известные как «тётушки», выступают уважаемыми лидерами и хранителями мира. Лорвинские боггарты ценят обмен знаниями и прошлым опытом внутри своих сообществ. Многие готовы идти на большие риски ради новых впечатлений, поэтому среди них нередко встречаются искатели приключений.
Лорвинские боггарты также обладают склонностью к магии. Те, кого тянет к изучению и использованию этих природных задатков, часто становятся друидами. В качестве альтернативы боггарт из Лорвина может найти своё призвание следопытом — особенно архетипа Странника Фей, — либо волшебником, в особенности школы Прорицания, поскольку боггарты известны любовью к получению сведений с помощью магии предсказаний.
В Тенеборье. Боггарты Тенеборья, как правило, имеют более острые и резкие черты, чем их лорвинские собратья, включая дополнительные пары рогов. Они также известны телесными модификациями, например, заклёпыванием бронированных пластин прямо к плоти. Общество боггартов Тенеборья хаотично и децентрализовано; их поселения немногочисленны и чаще всего находятся в изолированных или опасных местах. «Тётушки» Тенеборья странствуют по землям, встречая путников произвольными испытаниями, дарами или даже проклятиями.
Как и боггарты Лорвина, обитатели Тенеборья тянутся к магии. Такие боггарты могут становиться колдунами, чаще всего выбирая покровителя архифею; некоторые из них считают своим покровителем Исилу. Другие проявляют себя как чародеи и особенно склонны к проявлению сил через архетип Дикой магии.'::text
WHERE code = 'BOGGART'::text;

UPDATE rules.default_2024_race
SET description = 'Гномы – это волшебные существа, созданные богами изобретений, иллюзий и подземной жизни. Первые гномы редко встречались с другими народами из-за своей скрытной натуры и склонности жить в лесах и норах. Несмотря на малый рост, они компенсировали это умом, сбивая хищников с толку ловушками и лабиринтами туннелей. Они также научились магии от богов, таких как Гарл Златоблеск, Бэрван Дикий Странник и Баравар Теневой Плащ, которые навещали их в облике смертных. Эта магия в конечном итоге привела к возникновению родословных лесных и скальных гномов.
Гномы – это миниатюрные существа с большими глазами и заострёнными ушами, которые живут около 425 лет. Многие гномы любят ощущение крыши над головой, даже если эта «крыша» – не более чем шляпа.'::text
WHERE code = 'GNOME'::text;

UPDATE rules.default_2024_race
SET description = 'Громадные и внушительные, голиафы — это далёкие потомки великанов. Каждый голиаф носит в себе дары первых великанов — дары, которые проявляются в различных сверхъестественных благословениях, включая способность быстро увеличиваться и временно достигать размеров своих предков великанов.
Голиафы имеют физические характеристики, напоминающие их предков, великанов. Например, некоторые голиафы выглядят, как каменные великаны, в то время другие напоминают огненных великанов. Независимо от того, с какими великанами они связаны, голиафы проложили свой собственный путь в мультивселенной (свободные от внутренних конфликтов, которые веками терзали род великанов) и стремятся к вершинам, превышающим те, что достигли их предки.'::text
WHERE code = 'GOLIATH'::text;

UPDATE rules.default_2024_race
SET description = 'Дампиры — это живые люди, обладающие вампирскими способностями, но проклятые мрачной жаждой. Большинство дампиров испытывает тягу к крови, однако некоторые получают пропитание из снов, жизненной энергии или иных жизненно важных источников. Дампиры вынуждены делать выбор: сражаться, чтобы контролировать свою жажду, или поддаться хищным инстинктам.
Дампиры нередко появляются вследствие встреч с вампирами: одни являются потомками могущественного вампира, другие — частично преобразованы его укусом. Различные зловещие сделки и некромантические влияния также могут породить дампира. Независимо от происхождения, дампиры проявляют свою вампирскую природу по-разному, включая повышенную скорость и укус, высасывающий жизненные силы.'::text
WHERE code = 'DHAMPIR'::text;

UPDATE rules.default_2024_race
SET description = 'Дварфы были созданы из земли в древние времена божеством кузнечного дела. В разных мирах его называют по-разному — Морадин, Реоркс и так далее. Этот бог наделил дварфов способностью к работе с камнем и металлом, а также склонностью к жизни под землей. Он также сделал их стойкими, как горы, с продолжительностью жизни около 350 лет.
Коренастые и зачастую бородатые, первые дварфы вырезали города и крепости в горных склонах и под землёй. Их древнейшие легенды рассказывают о сражениях с монстрами, обитающими на вершинах гор и в Подземье, будь то исполинские гиганты или подземные чудовища. Вдохновленные этими историями, дварфы любой культуры часто поют о доблестных подвигах, особенно о том, как малые побеждают великих.
В некоторых мирах мультивселенной первые поселения дварфов были построены в холмах или горах, и семьи, ведущие своё происхождение от этих поселений, называют себя холмовыми или горными дварфами соответственно. В сеттингах Грейхок и Сага о копье существуют такие сообщества.'::text
WHERE code = 'DWARF'::text;

UPDATE rules.default_2024_race
SET description = 'Предки драконорождённых вылупились из яиц хроматических и металлических драконов. Согласно одной легенде, эти яйца были благословлены драконьими богами Бахамутом и Тиамат, которые хотели населить мультивселенную существами, созданными по их образу и подобию. Другая история утверждает, что драконы создали первых драконорождённых без благословения богов. Как бы то ни было, драконорождённые обрели своё место на Материальном плане.
Драконорождённые выглядят как бескрылые, двуногие драконы, покрытые чешуей, с яркими глазами, крепким телосложением и рогами на голове, а их окраска и другие особенности напоминают их драконьих предков.'::text
WHERE code = 'DRAGONBORN'::text;

UPDATE rules.default_2024_race
SET description = 'Имея постоянно меняющуюся внешность, Изменяющиеся живут среди самых разных народов, оставаясь незамеченными. Каждый Изменяющийся способен сверхъестественным образом принять любой облик, какой пожелает. Для некоторых Изменяющихся новый облик может отражать грань их собственной души.
Первые Изменяющиеся в Мультивселенной появились в Фейвейлде, и чудесная, изменчивая сущность этого плана по-прежнему живёт в них — даже в тех, кто никогда не ступал в владения фей.
В своём истинном облике Изменяющиеся выглядят блеклыми, их черты почти лишены деталей. Увидеть их в таком виде — большая редкость, ведь типичный Изменяющийся меняет форму так же легко, как другие меняют одежду. Однако многие Изменяющиеся создают личности с глубиной: выстраивают персону со своей историей и убеждениями, соответствующими каждому облику. Изменяющийся-искатель приключений может иметь персоны для разных ситуаций — переговоров, расследований или боя.
Несколько Изменяющихся могут пользоваться одной и той же персоной. Иногда персоны могут даже передаваться по наследству, позволяя молодому Изменяющемуся пользоваться связями, установленных предыдущими носителями этой персоны.'::text
WHERE code = 'CHANGELING'::text;

UPDATE rules.default_2024_race
SET description = 'Изменяющиеся Лорвина — харизматичные оборотни, способные грубо имитировать облик существ и растений. Однако, в отличие от большинства оборотней, их врождённые способности не позволяют им по-настоящему маскироваться; их превращения носят исключительно поверхностный характер.
Независимо от принятой формы, лорвинские изменяющиеся сохраняют свои ключевые черты: сине-зелёную кожу, пучки меха, похожего на щупальца, и выпуклые жёлтые глаза со щелевидными зрачками. Истинную сущность изменяющегося — будь то глазастое дерево, бирюзовый олень или мохнатый валун — всегда легко распознать. Эти подделки настолько очевидны, что многие жители Лорвина находят их необъяснимо очаровательными.
Изменяющиеся Лорвина обитают в огромной мистической пещере под названием Грот Велис Вел (см. главу 2). Раз в год многие из них совершают паломничество в грот, чтобы поразмышлять о своих прошлых деяниях.'::text
WHERE code = 'LORWYN_CHANGELING'::text;

UPDATE rules.default_2024_race
SET description = 'Калаштары (произносится как «кала́ш-тар») возникли из союза людей и отступников-квори — духов с плана сновидений. Калаштары выглядят как люди, но их духовная связь проявляется по-разному. У них симметричные, слегка угловатые черты лица, а глаза нередко светятся, когда они сосредоточены или испытывают сильные эмоции.
Калаштары не могут напрямую общаться со своими духами-квори. Скорее, калаштар ощущает их как источник инстинктов и вдохновения, черпая фрагменты воспоминаний духов во время сна. Эта связь наделяет калаштаров слабыми псионическими способностями и защищает от псионических атак.'::text
WHERE code = 'KALASHTAR'::text;

UPDATE rules.default_2024_race
SET description = 'Киткины — это невысокий народ с крепкими ногами, длинными руками и прочным телосложением. Их широкие лица, округлые уши и большие выразительные глаза придают им отдалённо медвежий облик.
Большинство киткинов связаны эмпатической сетью, позволяющей ощущать чувства находящихся рядом сородичей. Благодаря этой связи многие киткины безоговорочно доверяют друг другу.
Некоторые киткины временно или даже навсегда отстраняются от этой эмпатической сети по разным причинам, нередко из-за травм, полученных во время фирексийского вторжения (см. «Историю Лорвина–Тенеборья»). Несмотря на это, киткины обычно считают предательство своих одним из самых тяжких преступлений.
В Лорвине. Лорвинские киткины живут в пасторальных деревнях, называемых клаханами, и охотно принимают чужаков в свои общины. Они собирают своё культурное наследие в фолианте, известном как Книга Кита и Родни. Кроме того, они часто придерживаются множества суеверий, особенно связанных с лорвинскими воплощениями природы.
В Тенеборье. Киткины Тенеборья более замкнуты и ксенофобны. В основном они обитают в укреплённых поселениях, называемых доунами, где действуют строгие обычаи, поддерживающие социальный порядок. Лидеры киткинов Тенеборья внимательно следят за своими общинами, отслеживая любые признаки преступлений или измены.'::text
WHERE code = 'KITHKIN'::text;

UPDATE rules.default_2024_race
SET description = 'Кованные — это механические существа, созданные как оружие для участия в Последней войне. Неожиданный технологический прорыв привёл к появлению разумных существ из дерева и металла, которые, тем не менее, способны чувствовать боль и эмоции.
Кованные состоят из сочетания органических и неорганических материалов. Жильные корды, наполненные алхимическими жидкостями, служат им мышцами, обвивая каркас из стали, тёмнодрева или камня. Бронепластины формируют защитную внешнюю оболочку и укрепляют суставы. Чем сильнее кованный развивает свою индивидуальность, тем вероятнее он будет модифицировать своё тело, обращаясь к изобретателю, чтобы тот настроил внешний облик его лица, конечностей и покрытия.'::text
WHERE code = 'WARFORGED'::text;

UPDATE rules.default_2024_race
SET description = 'Орки связывают своё происхождение с Груумшем, могущественным богом, который бродил по бескрайним просторам Материального плана. Груумш наделил своих детей дарами, чтобы они могли путешествовать по огромным равнинам, обширным пещерам и бурным морям и противостоять монстрам, скрывающимся там. Даже когда орки начинают поклоняться другим богам, они сохраняют дары Груумша: выносливость, решимость и способность видеть в тьме.
В среднем орки высокие и широкоплечие. У них серая кожа, заострённые уши и выдающиеся нижние клыки, похожие на маленькие бивни. Молодым оркам в некоторых мирах рассказывают истории о великих путешествиях и испытаниях их предков. Вдохновлённые этими историями, многие орки задаются вопросом, когда Груумш призовёт их совершить героические подвиги древности и окажутся ли они достойны его благосклонности. Другие орки предпочитают оставить старые истории в прошлом и найти свой собственный путь.'::text
WHERE code = 'ORC'::text;

UPDATE rules.default_2024_race
SET description = 'Полурослики находятся под покровительством богов, ценящих жизнь, дом и семейный очаг, поэтому они стремятся к спокойным сельским местам, где семья и община помогают формировать их жизнь. Тем не менее, многие полурослики обладают смелым и авантюрным духом, который ведёт их в путешествия, давая возможность исследовать большой мир и находить новых друзей на этом пути. Их размер, сопоставимый с размером человеческого ребенка, позволяет им незаметно проходить через толпу и пробираться через узкие пространства.
Любой, кто проводил время рядом с полуросликами, особенно с полуросликами-приключенцами, наверняка становился свидетелем легендарного «везения полуросликов» в действии. Когда полурослик оказывается в смертельной опасности, то кажется, что неведомая сила вмешивается и помогает ему. Многие полурослики верят в силу удачи и приписывают этот необычный дар одному или нескольким своим благожелательным богам, включая Йондаллу, Брандобариса и Чармалейн. Возможно, этот дар также способствует их долгожительству (около 150 лет).
Сообщества полуросликов бывают самых разных видов. На каждый укромный уголок, спрятанный в нетронутой части мира, найдётся преступный синдикат, как, например, клан Боромар из сеттинга Эберрон, или местная банда полуросликов, как в сеттинге Тёмное солнце.
Полурослики, которые предпочитают жить под землёй, иногда называются коренастыми или стойкими полуросликами. Кочевые полурослики, а также те, кто живет среди людей и других высоких народов, иногда называются легконогими или высокорослыми полуросликами.'::text
WHERE code = 'HALFLING'::text;

UPDATE rules.default_2024_race
SET description = 'Раймкины происходят как из Лорвина, так и из Тенеборья, хотя первые раймкины возникли из флеймкинов во время вторжения Фирексии (см. «История Лорвина—Шэдоумура» во введении). Эти флеймкины подходили к проблемам с холодной логикой и отвергали импульсивные, реакционные решения. В результате магическое пламя, охватывавшее их тела, приобрело ледяную природу, и они стали раймкинами.
Как и флеймкины, раймкины обладают врождённой магией, однако пламя, которое они призывают, горит ледяным голубым светом, а не раскалённо-красным. Более того, эти «пламёна» излучают пронизывающий холод вместо обжигающего жара. Этот эффект поверхностно распространяется и на предметы, к которым прикасается раймкин: любые доспехи, которые он носит, и оружие, которым он владеет, покрываются слоями колючего, но безвредного изморози.'::text
WHERE code = 'RIMEKIN'::text;

UPDATE rules.default_2024_race
SET description = 'Тифлинги либо рождаются на Нижних планах, либо имеют предков исчадий оттуда. Тифлинг связан кровью с дьяволом, демоном или другим злобным существом. Эта связь с Нижними планами — зловещее наследие тифлинга, которое обещает силу, но не влияет на моральные устои тифлинга.
Тифлинг сам решает, принять или отвергнуть своё зловещее наследие. Описания 3 наследий приведены ниже.'::text
WHERE code = 'TIEFLING'::text;

UPDATE rules.default_2024_race
SET description = 'Флеймкины — это существа, созданные из двух ключевых элементов творения: огня и камня. В результате многие флеймкины ощущают сильную связь с природным миром. Их тела излучают безвредное магическое пламя, при этом они обладают врождённой магией, позволяющей создавать горящие огни во множестве форм.
Флеймкины считают самопознание и самовыражение высшими устремлениями и верят, что самореализация — самое важное, что индивид может совершить в своей жизни. Этот пожизненный путь они называют Путём Пламени.
Флеймкины обитают как в Лорвине, так и в Тенеборье. Физически и культурно они схожи в обеих землях.
Угли. В Тенеборье некоторых флеймкинов, подавивших свои пылкие эмоции, называют Углями, поскольку их магическое пламя ослабло. Хотя они всё ещё обладают огненными способностями, такие Угли визуально заметно отличаются от других флеймкинов. Со временем некоторые из них вновь разгораются ярким пламенем, тогда как другие превращаются в римкинов, о которых рассказано далее в этой главе.'::text
WHERE code = 'FLAMEKIN'::text;

UPDATE rules.default_2024_race
SET description = 'Известные своим озорством, фэйри напоминают насекомых с гуманоидными чертами. Их размеры и форма могут различаться, но все они обладают усиками, чёрными глазами, хитиновой кожей, а также насекомоподобными ногами и крыльями. Каждая фэйри рождается из цветка и обладает врождённой магией, которую многие из них используют для розыгрышей.
Некоторые фэйри Лорвина служат королеве Оуре, провозгласившей себя правительницей фэйри. Однако не все фэйри признают её власть. В Тенеборье фэйри могут вместо этого почитать королеву Марален — эльфийку, свергнувшую прежнюю королеву фэйри и, по мнению некоторых, положившую начало столкновению Лорвина и Тенеборья (подробнее см. «Историю Лорвина–Тенеборья» во введении).'::text
WHERE code = 'FAERIE'::text;

UPDATE rules.default_2024_race
SET description = 'На протяжении столетий те, кто произошёл от людей и эльфов, сформировали в Корвае собственные общины и традиции. Подъём Домов Лирандар и Медани укрепил эту идентичность. Члены этих общин называют себя Хоравар, что на эльфийском означает «дети Корвара», так как им не нравится термин «полуэльф».
Многие хоравары исповедуют идею «моста между мирами», считая, что их призвание — способствовать общению и сотрудничеству между представителями разных культур и народов. Хоравары, следующие этой философии, часто становятся бардами, дипломатами, посредниками или переводчиками.
Другие, очарованные своей давней связью с феями, стремятся построить мост между Материальным Планом и Фейвилдом Теланиса. Такие хоравары нередко становятся друидами или колдунами с покровителями—архифеями.'::text
WHERE code = 'KHORAVAR'::text;

UPDATE rules.default_2024_race
SET description = 'Встречающиеся по всей мультивселенной, люди столь же разнообразны, сколь многочисленны, и они стремятся достичь как можно большего за отведённые им годы. Их амбиции и изобретательность вызывают восхищение, уважение и страх во многих мирах.
Люди разнообразны внешне, как и жители Земли, и у них множество богов. Учёные спорят о происхождении человечества, но одно из самых ранних известных скоплений людей, как говорят, произошло из Сигила — торообразном городе в центре мультивселенной, месте, где родился Общий язык. Оттуда люди могли распространиться по всем уголкам мультивселенной, неся с собой космополитизм Города дверей.'::text
WHERE code = 'HUMAN'::text;

UPDATE rules.default_2024_race
SET description = 'Шифтеры — иногда называемых «затронутым оборотнем» (weretouched) — ведут свой род от людей, заболевших полной или частичной ликантропией. Эти гуманойдные существа с животными чертами не способны изменять форму полностью, но могут временно усилить свои звериные особенности — процесс, который они называют «сдвигом» (shifting).
Шифтеры похожи на людей по росту и телосложению, но обычно более жилистые и гибкие. Их черты лица носят звериный оттенок: крупные глаза, заострённые уши; у большинства шифтеров также выдающиеся клыки. Волосы, по текстуре напоминающие шерсть, растут у них почти на всём теле. Хотя внешний вид шифтера может напоминать животное, даже в своём наиболее диком состоянии он остаётся явно различимым как Гуманоид.'::text
WHERE code = 'SHIFTER'::text;

UPDATE rules.default_2024_race
SET description = 'Эльфы мира Лорвина–Тенеборья обладают чёрными глазами без зрачков, изогнутыми рогами, ногами, заканчивающимися раздвоенными копытами, и заострёнными ушами. Эльфы Лорвина заметно отличаются от своих собратьев из Тенеборья как внешне, так и культурно.
В Лорвине. Рога лорвинских эльфов короткие, как у козла, или изогнутые, как у барана, но всегда ребристые. Их заострённые уши длинные и тонкие.
В Лорвине эльфы превыше всего ценят красоту, хотя то, что конкретный эльф считает прекрасным, может казаться произвольным. Некоторые лорвинские эльфы присваивают себе власть над другими народами земли, опираясь в своих притязаниях на былое величие павшей империи.
Эти эльфы возлагают вину за падение своей империи на внешние угрозы, особенно на вторжение фирексийцев (см. «История Лорвина–Тенеборья»). Хотя это вторжение стало смертельным ударом для империи, самодовольство её народа и нежелание сотрудничать с другими видами уже ранее привели к упадку.
В Тенеборье. Рога эльфов Тенеборья длинные, волнистые и покрыты грубой, шипастой текстурой. Их заострённые уши, как правило, длиннее, чем у лорвинских собратьев.
Подобно эльфам Лорвина, эльфы Тенеборья оберегают красоту, однако их представление о «прекрасном» может быть абстрактным. Многие из них считают, что красота приобретается или утрачивается в зависимости от поступков; особенно высокими формами красоты они считают героизм и самопожертвование.
Искатели цветения — это эльфы Тенеборья, которые изучают и исследуют Лорвин. Каждый из них носит Реликварий Сумерек (см. введение). Наряду с Хранителями пути — эльфами Тенеборья, странствующими по своему миру в поисках прекрасного, — искатели цветения считаются одними из самых надёжных и почитаемых членов своего общества.'::text
WHERE code = 'ELF_LFL'::text;

UPDATE rules.default_2024_race
SET description = 'Созданные богом Кореллоном, первые эльфы могли менять свои формы по своему желанию. Они утратили эту способность, когда Кореллон проклял их за сговор с божеством Лолс, которая пыталась, но не смогла узурпировать власть Кореллона. Когда Лолс была низвергнута в Бездну, большинство эльфов отвергли её и заслужили прощение Кореллона, но то, что Кореллон у них отнял, было утрачено навсегда.
Потеряв способность изменять форму по своему желанию, эльфы отступили в Страну фей, где их печаль только усилилась под влиянием этого плана. Со временем любопытство привело многих из них к исследованию других измерений, включая миры Материального плана. Эльфы обладают заострёнными ушами и не имеют растительности на лице и теле. Они живут около 750 лет и не спят, а вместо этого входят в транс, когда нуждаются в отдыхе. В этом состоянии они остаются осведомлёнными о своём окружении, погружаясь в воспоминания и медитации.
Окружающая среда постепенно трансформирует эльфов, если они живут в ней более тысячи лет, и наделяет их определённой магией. Дроу, высшие эльфы и лесные эльфы — примеры эльфов, подвергшихся таким изменениям.'::text
WHERE code = 'ELF_PHB'::text;

